from datetime import datetime
import hashlib
import secrets


class InsufficientFundsError(Exception):
    pass


class InvalidTransactionError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class TransactionProcessor:
    def __init__(self):
        self._accounts: Dict[str, Decimal] = {}
        self._locks: Dict[str, threading.Lock] = {}
        self._transaction_log = []
        self._global_lock = threading.Lock()
    
    def create_account(self, account_id: str, initial_balance: Decimal = Decimal('0')) -> bool:
        if not isinstance(initial_balance, Decimal):
            initial_balance = Decimal(str(initial_balance))
        
        if initial_balance < 0:
            raise InvalidTransactionError("Initial balance cannot be negative")
        
        with self._global_lock:
            if account_id in self._accounts:
                return False
            self._accounts[account_id] = initial_balance
            self._locks[account_id] = threading.Lock()
            return True
    
    def get_balance(self, account_id: str) -> Decimal:
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} does not exist")
            return self._accounts[account_id]
    
    def deposit(self, account_id: str, amount: Decimal, description: str = "") -> str:
        if not isinstance(amount, Decimal):
            amount = Decimal(str(amount))
        
        if amount <= 0:
            raise InvalidTransactionError("Deposit amount must be positive")
        
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} does not exist")
            account_lock = self._locks[account_id]
        
        with account_lock:
            self._accounts[account_id] += amount
            transaction_id = self._generate_transaction_id()
            self._log_transaction(
                transaction_id=transaction_id,
                transaction_type="DEPOSIT",
                from_account=None,
                to_account=account_id,
                amount=amount,
                description=description
            )
            return transaction_id
    
    def withdraw(self, account_id: str, amount: Decimal, description: str = "") -> str:
        if not isinstance(amount, Decimal):
            amount = Decimal(str(amount))
        
        if amount <= 0:
            raise InvalidTransactionError("Withdrawal amount must be positive")
        
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} does not exist")
            account_lock = self._locks[account_id]
        
        with account_lock:
            if self._accounts[account_id] < amount:
                raise InsufficientFundsError(
                    f"Insufficient funds in account {account_id}. "
                    f"Balance: {self._accounts[account_id]}, Requested: {amount}"
                )
            
            self._accounts[account_id] -= amount
            transaction_id = self._generate_transaction_id()
            self._log_transaction(
                transaction_id=transaction_id,
                transaction_type="WITHDRAWAL",
                from_account=account_id,
                to_account=None,
                amount=amount,
                description=description
            )
            return transaction_id
    
    def transfer(self, from_account: str, to_account: str, amount: Decimal, description: str = "") -> str:
        if not isinstance(amount, Decimal):
            amount = Decimal(str(amount))
        
        if amount <= 0:
            raise InvalidTransactionError("Transfer amount must be positive")
        
        if from_account == to_account:
            raise InvalidTransactionError("Cannot transfer to the same account")
        
        with self._global_lock:
            if from_account not in self._accounts:
                raise AccountNotFoundError(f"Account {from_account} does not exist")
            if to_account not in self._accounts:
                raise AccountNotFoundError(f"Account {to_account} does not exist")
            
            lock1 = self._locks[from_account]
            lock2 = self._locks[to_account]
        
        first_lock, second_lock = (lock1, lock2) if from_account < to_account else (lock2, lock1)
        
        with first_lock:
            with second_lock:
                if self._accounts[from_account] < amount:
                    raise InsufficientFundsError(
                        f"Insufficient funds in account {from_account}. "
                        f"Balance: {self._accounts[from_account]}, Requested: {amount}"
                    )
                
                self._accounts[from_account] -= amount
                self._accounts[to_account] += amount
                
                transaction_id = self._generate_transaction_id()
                self._log_transaction(
                    transaction_id=transaction_id,
                    transaction_type="TRANSFER",
                    from_account=from_account,
                    to_account=to_account,
                    amount=amount,
                    description=description
                )
                return transaction_id
    
    def _generate_transaction_id(self) -> str:
        random_bytes = secrets.token_bytes(16)
        timestamp = str(datetime.utcnow().timestamp()).encode()
        hash_input = random_bytes + timestamp
        return hashlib.sha256(hash_input).hexdigest()[:16]
    
    def _log_transaction(self, transaction_id: str, transaction_type: str, 
                        from_account: Optional[str], to_account: Optional[str],
                        amount: Decimal, description: str):
        log_entry = {
            'transaction_id': transaction_id,
            'timestamp': datetime.utcnow().isoformat(),
            'type': transaction_type,
            'from_account': from_account,
            'to_account': to_account,
            'amount': str(amount),
            'description': description
        }
        self._transaction_log.append(log_entry)
    
    def get_transaction_history(self, account_id: str) -> list:
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} does not exist")
        
        return [
            log for log in self._transaction_log
            if log['from_account'] == account_id or log['to_account'] == account_id
        ]


def process_transaction(processor: TransactionProcessor, transaction_type: str, 
                       account_id: str, amount: Decimal, 
                       to_account: Optional[str] = None, description: str = "") -> str:
    if transaction_type == "deposit":
        return processor.deposit(account_id, amount, description)
    elif transaction_type == "withdraw":
        return processor.withdraw(account_id, amount, description)
    elif transaction_type == "transfer":
        if to_account is None:
            raise InvalidTransactionError("Transfer requires a destination account")
        return processor.transfer(account_id, to_account, amount, description)
    else:
        raise InvalidTransactionError(f"Unknown transaction type: {transaction_type}")